import{_ as a,C as B,o,c as r,k as A,a as t,E as n,e as i,af as g}from"./chunks/framework.BvYvR_Rg.js";const b=JSON.parse('{"title":"如何自建IoT实验室（一）","description":"","frontmatter":{"title":"如何自建IoT实验室（一）","date":"2020-03-05T19:17:23.000Z","category":"IoT","tags":["IoT"]},"headers":[],"relativePath":"posts/如何自建IoT实验室（一）.md","filePath":"posts/如何自建IoT实验室（一）.md","lastUpdated":1783008259000}'),s={name:"posts/如何自建IoT实验室（一）.md"};function m(l,E,h,p,c,C){const e=B("font");return o(),r("div",null,[E[2]||(E[2]=A("h1",{id:"背景",tabindex:"-1"},[t("背景 "),A("a",{class:"header-anchor",href:"#背景","aria-label":'Permalink to "背景"'},"​")],-1)),E[3]||(E[3]=A("p",null,[t("IoT的理念炒了这么多年，最近几年算是真正火热起来，同样，IoT安全也从多年前的冷门变成了热门。但IoT安全研究是一项"),A("code",null,"高成本"),t("活动，很多同学对这一块也很茫然，既花了冤枉钱，也浪费了时间，走了弯路，这里就给大家介绍下如何自建IoT安全实验室。")],-1)),E[4]||(E[4]=A("h1",{id:"_0x10-基本硬件设备",tabindex:"-1"},[t("0x10 基本硬件设备 "),A("a",{class:"header-anchor",href:"#_0x10-基本硬件设备","aria-label":'Permalink to "0x10 基本硬件设备"'},"​")],-1)),A("p",null,[E[1]||(E[1]=t("纯软件模拟的玩法是最省成本的，但如果真的想在IoT领域好好玩耍，该有的投入还得有。 ",-1)),A("strong",null,[n(e,{color:"red"},{default:i(()=>[...E[0]||(E[0]=[t("在我的著作《硬件安全攻防大揭秘》一书中也有很多讲解，大家可以参阅！！",-1)])]),_:1})])]),E[5]||(E[5]=g('<p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575929.png" alt=""></p><h2 id="_0x11-电脑" tabindex="-1">0x11 电脑 <a class="header-anchor" href="#_0x11-电脑" aria-label="Permalink to &quot;0x11 电脑&quot;">​</a></h2><p>这个不用说，大家都懂， 一台高性能的电脑是基本盘，因为你会需要运行各种vmware虚拟机跑各种系统各种镜像，所以，一台高性能的台式机或者笔记本那是必须的，内存得大一点。 如果有条件，2/3/4/5台电脑或者vps也不嫌多，笔记本、小主机、大台式、服务器，多多益善。 毕竟还是需要经常编译或者交叉编译的，高性能的机器能节省你非常宝贵的时间的。 如果囊中羞涩，可以在淘宝、咸鱼买配件攒一台单路或者多路的工作站，x58 x79 x99，从老到新，总有一款志强机器适合你！</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575931.png" alt=""></p><h2 id="_0x12-网络" tabindex="-1">0x12 网络 <a class="header-anchor" href="#_0x12-网络" aria-label="Permalink to &quot;0x12 网络&quot;">​</a></h2><p>这个也不用多说，基本盘。自建VPS建梯子什么的也不用多说，毕竟很多资料都得靠google，百度？先过滤掉那些垃圾广告排名再看。 再就是很多软件编译时候需要从网络下载依赖，下载不到或者下载太慢，既浪费时间，也影响进度，更影响心情。 建议自建VPS，买的既不靠谱，也不安全，都是做安全的，不解释。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575932.png" alt=""></p><p>如果VPS带宽很渣，那建议自己准备一个大容量NAS，有条件建议买QNAP的，群晖的性价比太差。没条件的可以DIY一台机器跑FreeNAS或者干脆就跑个Linux，我之前的博文有讲。黑群辉、路由器挂移动硬盘、树莓派什么的随便玩玩就行，重要的数据还是免了。 在这个大容量NAS里做本地源，将常用的Linux源、软件包都脱机下载到本地，自建本地镜像，这个可以节省大家大量的时间！</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575942.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575933.png" alt=""></p><h2 id="_0x13-拆机工具" tabindex="-1">0x13 拆机工具 <a class="header-anchor" href="#_0x13-拆机工具" aria-label="Permalink to &quot;0x13 拆机工具&quot;">​</a></h2><p>要玩IoT，拆各种设备这是基本能力。工欲善其事必先利其器，巧妇难为无米之炊，基本工具还得要的。 这里介绍一些最基本的，诸位按需选用。</p><h3 id="螺丝刀" tabindex="-1">螺丝刀 <a class="header-anchor" href="#螺丝刀" aria-label="Permalink to &quot;螺丝刀&quot;">​</a></h3><p>这里建议买螺丝刀套装，比如JAKEMY 杰科美 JM-6108 79合1套装，一套基本齐全。 有条件也能买德系、日系的，螺丝刀头更耐用。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575949.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575951.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575952.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575934.png" alt=""></p><p>如果要经常拆一些小设备，还需要一套精密螺丝刀，按需购买即可。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575970.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575937.png" alt=""></p><p>另外，一般还需要买一套加磁器，用于加磁消磁。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575935.png" alt=""></p><p>最后，有些精密设备，还需要用无感的塑料螺丝刀、陶瓷螺丝刀</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575940.png" alt=""></p><h3 id="老虎钳、尖嘴钳、斜口钳、水口钳、剥线钳、台钳" tabindex="-1">老虎钳、尖嘴钳、斜口钳、水口钳、剥线钳、台钳 <a class="header-anchor" href="#老虎钳、尖嘴钳、斜口钳、水口钳、剥线钳、台钳" aria-label="Permalink to &quot;老虎钳、尖嘴钳、斜口钳、水口钳、剥线钳、台钳&quot;">​</a></h3><p>淘宝随便买就行，经济允许买德系、日系的相对更耐用一些，但这一类工具也算耗材，便宜的随便用用也能用</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575936.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575950.png" alt=""></p><p>剥线钳，按需选用。 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575941.png" alt=""></p><p>各种类型、尺寸台钳按需选用。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575938.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575953.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575954.png" alt=""></p><h3 id="拆机片、撬棒、吸盘" tabindex="-1">拆机片、撬棒、吸盘 <a class="header-anchor" href="#拆机片、撬棒、吸盘" aria-label="Permalink to &quot;拆机片、撬棒、吸盘&quot;">​</a></h3><p>这种淘宝有很多手机拆机套装</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024575939.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576147.png" alt=""></p><h3 id="镊子" tabindex="-1">镊子 <a class="header-anchor" href="#镊子" aria-label="Permalink to &quot;镊子&quot;">​</a></h3><p>必备工具，各种规格都有，也是耗材，因为一个不小心就会翘弯、摔弯，便宜的也能用，但贵的还是得有几个</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576665.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576648.png" alt=""></p><p>如果要严格防静电，还需要塑料镊子</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576652.png" alt=""></p><h3 id="热熔胶枪" tabindex="-1">热熔胶枪 <a class="header-anchor" href="#热熔胶枪" aria-label="Permalink to &quot;热熔胶枪&quot;">​</a></h3><p>固定线材、熔接，很好用，要拆也有个小技巧，喷点酒精或者酒精棉擦擦，就可以用镊子取开。 功率越大融化越快，需要注意的是，胶棒一定要买高质量的！ 推荐这种带电池的，使用便捷。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576666.png" alt=""></p><h3 id="美工刀、电钻、电磨" tabindex="-1">美工刀、电钻、电磨 <a class="header-anchor" href="#美工刀、电钻、电磨" aria-label="Permalink to &quot;美工刀、电钻、电磨&quot;">​</a></h3><p>各种规格的美工刀、雕刻刀、手术刀，按需选用。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576700.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576655.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576660.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576661.png" alt=""></p><p>电动螺丝批、电钻，有条件买博世，没条件就随便买。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576663.png" alt=""></p><p>电磨也是按需选用，建议买套装。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576662.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576656.png" alt=""></p><h3 id="各种胶带" tabindex="-1">各种胶带 <a class="header-anchor" href="#各种胶带" aria-label="Permalink to &quot;各种胶带&quot;">​</a></h3><p>3M双面胶带、泡沫胶带、纤维胶带、隔热胶带、醋酸胶带。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576657.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576649.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576659.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576658.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576650.png" alt=""></p><h3 id="绝缘垫" tabindex="-1">绝缘垫 <a class="header-anchor" href="#绝缘垫" aria-label="Permalink to &quot;绝缘垫&quot;">​</a></h3><p>耐高温的绝缘台垫，保护桌面。可以买单块直接铺满工作台，也可以买多功能的</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576664.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576808.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576651.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576953.png" alt=""></p><h2 id="_0x14-仪器设备" tabindex="-1">0x14 仪器设备 <a class="header-anchor" href="#_0x14-仪器设备" aria-label="Permalink to &quot;0x14 仪器设备&quot;">​</a></h2><p>这里就讲讲玩IoT安全需要一些基本硬件设备，比如电烙铁、热风枪、万用表、编程器、逻辑分析仪等等。</p><h3 id="电烙铁、热风枪、bga返修台" tabindex="-1">电烙铁、热风枪、BGA返修台 <a class="header-anchor" href="#电烙铁、热风枪、bga返修台" aria-label="Permalink to &quot;电烙铁、热风枪、BGA返修台&quot;">​</a></h3><p>飞线、拆焊芯片、电子元器件必备工具。</p><p>有条件买HAKKO白光的，真的好用！记得买刀头！ 常规用FX888D，有精密小设备用FX951配T12-KU小刀头。 买白光最好找正规代理商，假货不少，尤其是手柄和刀头，很多假货。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576972.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576955.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576957.png" alt=""></p><p>没条件买国产的安泰信、快克也行。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576959.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577311.png" alt=""></p><p>还有DIY的白菜T12焊台、正点原子T100烙铁，也都凑合。不过，烙铁这种东西，耐用和好用仁者见仁智者见智，我是最爱白光，感觉最舒服最顺手。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024576958.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577136.png" alt=""></p><p>另外，要拆Flash用电热镊子非常方便，比如白光FM203配FM2023电热镊子，再选用适当的焊咀。</p><p><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577314.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577315.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577144.png" alt=""></p><p>还有热风枪，用来拆QFP、QFN等芯片非常好用。 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577291.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577312.png" alt=""></p><p>最后，再说bga返修台，红外还是热风，按需选用。 这里推荐一个多合一的。烙铁、热风枪、红外返修台都有，虽然都很一般，但胜在一套集成，方便。 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577313.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577307.png" alt=""></p><p>焊锡丝推荐买山崎SANKI的，直径按需选用，我通常0.3\\0.8\\1mm都会备一点。 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577308.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577309.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577310.png" alt=""></p><p>飞线，各种颜色的飞线、漆包线随便买了，都备一点 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577316.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577361.png" alt=""></p><p>至于其他的什么锡丝架、吸锡器、高温海绵看着买就行。 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577528.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577526.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577549.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577563.png" alt=""></p><h3 id="编程器" tabindex="-1">编程器 <a class="header-anchor" href="#编程器" aria-label="Permalink to &quot;编程器&quot;">​</a></h3><p>玩IoT安全，拆完芯片后dump固件是基本操作，那就需要编程器了，这里推荐几款相对好用的。</p><p>Gzut的读写EEPROM、SPI Flash性价比很高，山寨无数。 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577559.png" alt=""></p><p>RT809H，维修界常用。 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577560.png" alt=""></p><p>ZLG SmartPRO 5000U Plus通用编程器，很多MCU都能读，没有的官方也能适配，但支持效率非常低。 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577561.png" alt=""></p><p>西尔特6100N，支持的芯片非常非常多，但厂家很坑，一个是限制网上售价必须高于xxx，再就是很多要买他们加了认证芯片的底座 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577562.png" alt=""></p><p>配合烧写夹、烧写座 <img src="http://qn.white-alone.com/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4/hexo_1583422629478.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577814.png" alt=""></p><h3 id="调试器" tabindex="-1">调试器 <a class="header-anchor" href="#调试器" aria-label="Permalink to &quot;调试器&quot;">​</a></h3><p>J-link，这个不用多说，都懂，这里大家要感谢曹总，让我们能用上廉价的V10版本！！！ 当然，有条件的还是支持正版，SEGGER这么牛逼，还是要支持的。 另外Pro版也不错。 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577808.png" alt=""></p><p>STLink V2、V3，V2版就不说了，新出的V3版很不错！ <img src="http://qn.white-alone.com/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4/hexo_1583422630057.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577809.png" alt=""></p><p>至于其他的比如CCDebugger、AVRISP mkII等其他编程器，按需选用 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577817.png" alt=""><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577816.png" alt=""></p><p>如果要搞CPLD、FPGA，推荐北京一个老哥哥设计的<a href="https://item.taobao.com/item.htm?spm=a1z10.3-c.w4002-2469271744.54.73785a06lk9ca5&amp;id=581542782890" target="_blank" rel="noreferrer">三合一下载器</a><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577815.png" alt=""></p><h3 id="万用表" tabindex="-1">万用表 <a class="header-anchor" href="#万用表" aria-label="Permalink to &quot;万用表&quot;">​</a></h3><p>不解释，测电路通断、电阻电容电感必须。 推荐Fluke，具体哪个型号看自己的经济实力和精度需求。条件不允许就随便买了，都能用，就是好不好用的区别。 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577810.png" alt=""></p><p>如果对精度要求高就买台表。 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577811.png" alt=""></p><h3 id="逻辑分析仪" tabindex="-1">逻辑分析仪 <a class="header-anchor" href="#逻辑分析仪" aria-label="Permalink to &quot;逻辑分析仪&quot;">​</a></h3><p>要数字信号、分析芯片间通信，逻辑分析仪是必须的。</p><p>Saleae做的非常棒，低速可以用<a href="https://item.taobao.com/item.htm?spm=a1z10.3-c.w4002-2469271744.42.73785a06lk9ca5&amp;id=37493618604" target="_blank" rel="noreferrer">国产Saleae16</a><img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577812.png" alt=""></p><p>高速可以也可以用北京这哥哥设计的<a href="https://item.taobao.com/item.htm?spm=a1z10.3-c.w4002-2469271744.72.73785a06lk9ca5&amp;id=601831958682" target="_blank" rel="noreferrer">500M 32通道逻辑分析仪</a>，去年刚升级了硬件，更牛逼了。 <img src="https://raw.githubusercontent.com/white-alone/blog_img/master/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4%EF%BC%88%E4%B8%80%EF%BC%89/1591024577813.png" alt=""><img src="http://qn.white-alone.com/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4/hexo_1583422629712.png" alt=""></p><p>当然，有条件还是买Saleae正版的设备 <img src="http://qn.white-alone.com/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4/hexo_1583422629638.png" alt=""></p><p>另外，周立功的逻辑分析仪也很不错。 <img src="http://qn.white-alone.com/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4/hexo_1583422629659.png" alt=""><img src="http://qn.white-alone.com/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4/hexo_1583422629725.png" alt=""></p><p>还有梦源实验室的DSLogic也还行。 <img src="http://qn.white-alone.com/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4/hexo_1583422629726.png" alt=""></p><p>如果只是玩特别低速的信号，有一款手持的比较有意思。不过，这种也就玩玩而已，不太好用。 <img src="http://qn.white-alone.com/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4/hexo_1583422629727.png" alt=""></p><h3 id="示波器" tabindex="-1">示波器 <a class="header-anchor" href="#示波器" aria-label="Permalink to &quot;示波器&quot;">​</a></h3><p>这个就不用说了，测各种信号需要，但这个属于仪器了，入门的一两百M的就随便玩玩，好的都是几十上百万的。 泰克、安捷伦、国产的周立功、普源等都不错，条件允许可以搞个好点的。 <img src="http://qn.white-alone.com/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4/hexo_1583422630066.png" alt=""><img src="http://qn.white-alone.com/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4/hexo_1583422630058.png" alt=""></p><p>另外梦源实验室的DSCope便携示波器也能凑合用。 <img src="http://qn.white-alone.com/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4/hexo_1583422630064.png" alt=""></p><p>再就是DS213便携示波器也比较有意思，当然性能是渣渣。 <img src="http://qn.white-alone.com/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4/hexo_1583422630067.png" alt=""><img src="http://qn.white-alone.com/%E5%A6%82%E4%BD%95%E8%87%AA%E5%BB%BAIoT%E5%AE%9E%E9%AA%8C%E5%AE%A4/hexo_1583422630077.png" alt=""></p>',94))])}const w=a(s,[["render",m]]);export{b as __pageData,w as default};
